1. Create a new application component <pre><code>// ./src/apps/my-new-application/my-new-application.jsx
import React from "react";
import PropTypes from "prop-types";
export function MyNewApplication({ text }) {
return (
&lt;h2&gt;{text}&lt;/h2&gt;
);
}
MyNewApplication.defaultProps = {
text: "The fastest man alive!"
};
MyNewApplication.propTypes = {
text: PropTypes.string
};
export default MyNewApplication;
</code></pre> 2. Create the entry component <pre><code>// ./src/apps/my-new-application/my-new-application.entry.jsx
import React from "react";
import PropTypes from "prop-types";
import MyNewApplication from "./my-new-application";
// The props of an entry is all of the data attributes that were
// set on the DOM element. See the section on "Naive app mount." for
// an example.
export function MyNewApplicationEntry(props) {
return &lt;MyNewApplication text='Might be from a server?' /&gt;;
}
export default MyNewApplicationEntry;
</code></pre> 3. Create the mount <pre><code>// ./src/apps/my-new-application/my-new-application.mount.js
import addMount from "../../core/addMount";
import MyNewApplication from "./my-new-application.entry";
addMount({ appName: "my-new-application", app: MyNewApplication });
</code></pre> 4. Add a story for local development <pre><code>// ./src/apps/my-new-application/my-new-application.dev.jsx
import React from "react";
import MyNewApplicationEntry from "./my-new-application.entry";
import MyNewApplication from "./my-new-application";
export default { title: "Apps|My new application" };
export function Entry() {
// Testing the version that will be shipped.
return &lt;MyNewApplicationEntry /&gt;;
}
export function WithoutData() {
// Play around with the application itself without server side data.
return &lt;MyNewApplication /&gt;;
}
</code></pre> 5. Run the development environment <pre><code>  yarn dev
</code></pre>  OR depending on your dev environment (docker or not)  <pre><code>  sudo yarn dev
</code></pre> <p>Voila! You browser should have opened and a storybook environment is ready for you to tinker around.</p>

1. Create an application specific stylesheet <pre><code>// ./src/apps/my-new-application/my-new-application.scss
.dpl-warm {
color: maroon;
}
</code></pre> 2. Add the class to your application <pre><code>// ./src/apps/my-new-application/my-new-application.jsx
import React from "react";
import PropTypes from "prop-types";
export function MyNewApplication({ text }) {
return (
&lt;h2 className='warm'&gt;{text}&lt;/h2&gt;
);
}
MyNewApplication.defaultProps = {
text: "The fastest man alive!"
};
MyNewApplication.propTypes = {
text: PropTypes.string
};
export default MyNewApplication;
</code></pre> 3. Import the scss into your story <pre><code>// ./src/apps/my-new-application/my-new-application.dev.jsx
import React from "react";
import MyNewApplicationEntry from "./my-new-application.entry";
import MyNewApplication from "./my-new-application";
import './my-new-application.scss';
export default { title: "Apps|My new application" };
export function Entry() {
// Testing the version that will be shipped.
return &lt;MyNewApplicationEntry /&gt;;
}
export function WithoutData() {
// Play around with the application itself without server side data.
return &lt;MyNewApplication /&gt;;
}
</code></pre> <p>Cowabunga! You now got styling in your application</p>

1. Create the atom <pre><code>// ./src/components/atoms/my-new-atom/my-new-atom.jsx
import React from "react";
import PropTypes from 'prop-types';
/**
 * A simple button.
 *
 * @export
 * @param {object} props
 * @returns {ReactNode}
 */
export function MyNewAtom({ className, children }) {
return &lt;button className={`btn ${className}`}&gt;{children}&lt;/button&gt;;
}
MyNewAtom.propTypes = {
className: PropTypes.string,
children: PropTypes.node.isRequired
}
MyNewAtom.defaultProps = {
className: ""
}
export default MyNewAtom;
</code></pre> 2. Create styles for the atom <pre><code>// ./src/components/atoms/my-new-atom/my-new-atom.scss
.dpl-btn {
color: blue;
}
</code></pre> 3. Import the atom's styles into the component stylesheet <pre><code>// ./src/components/components.scss
@import 'atoms/button/button.scss';
@import 'atoms/my-new-atom/my-new-atom.scss';
</code></pre> 4. Create a story for your atom <pre><code>// ./src/components/atoms/my-new-atom/my-new-atom.dev.jsx
import React from "react";
import MyNewAtom from "./my-new-atom";
export default { title: "Atoms|My new atom" };
export function WithText() {
return &lt;MyNewAtom&gt;Cick me!&lt;/MyNewAtom&gt;;
}
</code></pre> 5. Import the atom into the applications or other components where you would want to use it <pre><code>// ./src/apps/my-new-application/my-new-application.jsx
import React, {Fragment} from "react";
import PropTypes from "prop-types";
import MyNewAtom from "../../components/atom/my-new-atom/my-new-atom"
export function MyNewApplication({ text }) {
return (
&lt;Fragment&gt;
&lt;h2 className='warm'&gt;{text}&lt;/h2&gt;
&lt;MyNewAtom className='additional-class' /&gt;
&lt;/Fragment&gt;
);
}
MyNewApplication.defaultProps = {
text: "The fastest man alive!"
};
MyNewApplication.propTypes = {
text: PropTypes.string
};
export default MyNewApplication;
</code></pre> <p>Finito! You now know how to share code across applications</p>
